package main

import (
	"fmt"
	"sync"
)

type Bank struct {
	accounts map[string]float64
	mutex    sync.RWMutex
}

func NewBank() *Bank {
	return &Bank{
		accounts: make(map[string]float64),
	}
}

func (b *Bank) Deposit(account string, amount float64) {
	b.mutex.Lock()
	defer b.mutex.Unlock()
	b.accounts[account] += amount
}

func (b *Bank) Withdraw(account string, amount float64) bool {
	b.mutex.Lock()
	defer b.mutex.Unlock()
	if b.accounts[account] >= amount {
		b.accounts[account] -= amount
		return true
	}
	return false
}

func (b *Bank) CheckBalance(account string) float64 {
	b.mutex.RLock()
	defer b.mutex.RUnlock()
	return b.accounts[account]
}

func main() {
	bank := NewBank()

	var wg sync.WaitGroup

	wg.Add(3)
	go func() {
		defer wg.Done()
		bank.Deposit("123", 100.0)
	}()

	go func() {
		defer wg.Done()
		bank.Withdraw("123", 50.0)
	}()

	go func() {
		defer wg.Done()
		fmt.Println("Balance:", bank.CheckBalance("123"))
	}()

	wg.Wait()
	fmt.Println("Final Balance:", bank.CheckBalance("123"))
}